from flask import Flask, request, jsonify
import uuid
from werkzeug.urls import url_parse

app = Flask(__name__)
clients = {}
tokens = {}

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    base_url = data['baseURL']
    client_id = uuid.uuid4().hex
    
    clients[client_id] = {
        'baseURL': base_url,
        'redirectURIs': [],
    }
    
    return jsonify({'clientId': client_id}), 201

@app.route('/register/<string:client_id>', methods=['PUT'])
def update(client_id):
    data = request.get_json()
    redirect_uri = url_parse(data['redirectURI']).netloc + url_parse(data['redirectURI']).path
    
    if client_id not in clients:
        return jsonify({'error': 'Invalid client ID'}), 400
    
    for uri in clients[client_id]['redirectURIs']:
        if redirect_uri.startswith(uri):
            return jsonify({'message': 'Redirect URI already registered for this client'}), 200
    
    clients[client_id]['redirectURIs'].append(redirect_uri)
    return jsonify({'message': 'Redirect URI successfully registered for this client'}), 201

